//! Lean 4 source code emitter.
//!
//! Builds up Lean source files as strings and writes them to disk.

use std::fmt::Write as FmtWrite;
use std::path::Path;

use anyhow::{Context, Result};

/// A builder for a single Lean 4 source file.
pub struct LeanFile {
    /// The internal buffer. Public for `writeln!` usage in sibling modules.
    pub buf: String,
}

impl LeanFile {
    /// Creates a new Lean file with the `@generated` header.
    pub fn new(module_doc: &str) -> Self {
        let mut buf = String::with_capacity(4096);
        buf.push_str("-- @generated by uor-lean from uor-ontology \u{2014} do not edit manually\n");
        if !module_doc.is_empty() {
            buf.push_str("--\n");
            let _ = writeln!(buf, "-- {module_doc}");
        }
        buf.push('\n');
        Self { buf }
    }

    /// Appends a raw line.
    ///
    /// v0.2.1 Phase 7g.5: every emitted line is passed through
    /// `sanitize_lean_line` before being buffered. If a generator attempts
    /// to emit a banned primitive (`sorry`, `partial def`, `native_decide`,
    /// `unsafe`, `@[extern]`, `@[implemented_by]`, or an unauthorized
    /// `axiom`), the codegen binary panics with a clear error pointing at
    /// the offending line.
    pub fn line(&mut self, s: &str) {
        sanitize_lean_line(s);
        self.buf.push_str(s);
        self.buf.push('\n');
    }

    /// Appends a blank line.
    pub fn blank(&mut self) {
        self.buf.push('\n');
    }

    /// Appends a Lean 4 doc comment (`/-- ... -/`).
    pub fn doc_comment(&mut self, comment: &str) {
        let normalized = normalize_lean_comment(comment);
        let _ = writeln!(self.buf, "/-- {normalized} -/");
    }

    /// Appends an indented Lean 4 doc comment (2 spaces, for inside structure bodies).
    pub fn indented_doc_comment(&mut self, comment: &str) {
        let normalized = normalize_lean_comment(comment);
        let _ = writeln!(self.buf, "  /-- {normalized} -/");
    }

    /// Returns the built source as a string, with trailing whitespace trimmed.
    pub fn finish(self) -> String {
        let trimmed = self.buf.trim_end();
        format!("{trimmed}\n")
    }
}

/// Writes a Lean source file to disk, creating parent directories as needed.
///
/// # Errors
///
/// Returns an error if the directory cannot be created or the file cannot be written.
pub fn write_file(path: &Path, content: &str) -> Result<()> {
    if let Some(parent) = path.parent() {
        std::fs::create_dir_all(parent)
            .with_context(|| format!("Failed to create directory: {}", parent.display()))?;
    }
    std::fs::write(path, content)
        .with_context(|| format!("Failed to write: {}", path.display()))?;
    Ok(())
}

/// Normalizes a comment string for Lean 4 doc comments: collapses internal
/// whitespace runs and escapes Lean comment delimiters.
pub fn normalize_lean_comment(s: &str) -> String {
    let collapsed: String = s.split_whitespace().collect::<Vec<_>>().join(" ");
    // Break /- and -/ sequences with a space to prevent nested comment issues
    collapsed.replace("/-", "/ -").replace("-/", "- /")
}

/// Panics if the line contains any banned primitive. Comment-only lines
/// (starting with `--`) are allowed to mention the banned words so the
/// generator can still explain why they're forbidden in doc text.
///
/// `axiom` declarations are allowed only for the single whitelisted
/// `UOR_SEALED_PROVENANCE` identifier.
///
/// Panicking is the *intended* behaviour — the codegen binary should abort
/// loudly if any generator tries to emit a banned primitive. The crate's
/// `#![deny(clippy::panic)]` is overridden here for the specific sanitizer
/// path; no production code calls it in the success path.
///
/// v0.2.1 Phase 8b.6: pattern list lives in
/// [`crate::rigor_patterns::BANNED_PATTERNS`] as the single source of
/// truth shared with the conformance validator.
#[allow(clippy::panic)]
pub fn sanitize_lean_line(line: &str) {
    use crate::rigor_patterns::{ALLOWED_AXIOM, BANNED_PATTERNS};

    // Strip any trailing line comment before checking.
    let code = match line.find("--") {
        Some(idx) => &line[..idx],
        None => line,
    };

    // `axiom` whitelist check.
    if let Some(axiom_pos) = code.find("axiom ") {
        let rest = &code[axiom_pos + "axiom ".len()..];
        let ident_end = rest
            .find(|c: char| c.is_whitespace() || c == ':' || c == '(')
            .unwrap_or(rest.len());
        let ident = rest[..ident_end].trim();
        if ident != ALLOWED_AXIOM && !ident.is_empty() {
            panic!(
                "lean-codegen: attempted to emit unauthorized `axiom` \
                 declaration (only `{ALLOWED_AXIOM}` is whitelisted for \
                 Phase 7g.3 sealed-provenance): `{code}`"
            );
        }
    }

    for (pat, reason) in BANNED_PATTERNS {
        if code.contains(pat) {
            panic!(
                "lean-codegen: attempted to emit banned primitive: {reason}. \
                 Pattern `{pat}` matched in line: `{code}`"
            );
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn comment_delimiter_escaping() {
        assert_eq!(normalize_lean_comment("foo /- bar"), "foo / - bar");
        assert_eq!(normalize_lean_comment("foo -/ bar"), "foo - / bar");
    }

    #[test]
    fn whitespace_collapsing() {
        assert_eq!(normalize_lean_comment("a  b   c"), "a b c");
        assert_eq!(normalize_lean_comment("a\nb\tc"), "a b c");
    }

    #[test]
    fn generated_header() {
        let f = LeanFile::new("Test module.");
        let content = f.finish();
        assert!(content.starts_with("-- @generated by uor-lean"));
        assert!(content.contains("Test module."));
    }

    #[test]
    #[should_panic(expected = "`sorry` leaves a hole in the proof")]
    fn sanitize_panics_on_sorry() {
        sanitize_lean_line("def x : Nat := sorry");
    }

    #[test]
    #[should_panic(expected = "`partial def` is non-reducible")]
    fn sanitize_panics_on_partial_def() {
        sanitize_lean_line("partial def loop : Nat \u{2192} Nat := fun n => loop (n + 1)");
    }

    #[test]
    #[should_panic(expected = "`native_decide` trusts native code")]
    fn sanitize_panics_on_native_decide() {
        sanitize_lean_line("example : 2 + 2 = 4 := by native_decide");
    }

    #[test]
    #[should_panic(expected = "unauthorized `axiom`")]
    fn sanitize_panics_on_unauthorized_axiom() {
        sanitize_lean_line("axiom BadAxiom : False");
    }

    #[test]
    fn sanitize_allows_sealed_provenance_axiom() {
        sanitize_lean_line("axiom UOR_SEALED_PROVENANCE : True");
    }

    #[test]
    fn sanitize_allows_sorry_in_comment() {
        sanitize_lean_line("-- TODO: avoid sorry in this file");
    }
}
